export const COURSES: CatalogCourse[] = [
  { code: "ACC0012", name_en: "Business Project", name_ar: "مشروع الأعمال", credit_hours: 4, course_type: "lab", language: "en", programs: ["diploma-accounting"], prerequisites: [], description_en: "Students draw upon knowledge learned throughout the program to participate in weekly duties that simulate authentic business practices. Students integrate and apply their knowledge of fundamental accounting and taxation to complete various tasks using professional business writing skills and computer software. Prerequisite(s): ACC2209 and ACC2233 and ACC2385" },
  { code: "ACC0014", name_en: "Accounting for Small Business", name_ar: "المحاسبة للشركات الصغيرة", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: [], description_en: "Students develop the ability to identify and work collaboratively and effectively with their accountant and bookkeeper through their business launch and operations. Topics include balance sheets, income statements, journalizing in the general journal, general ledger and special journals, proper banking procedures, cash control protocols and government related employee payroll and tax requirements." },
  { code: "ACC2201", name_en: "Financial Accounting, I", name_ar: "المحاسبة المالية 1", credit_hours: 5, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting"], prerequisites: [], description_en: "This is the first course in a series of three financial accounting courses where students learn the fundamentals necessary to enter the field of accounting. Students learn basic financial statements and capture financial information. Through a combination of practical exercises and the use of computer software, students develop an understanding of essential accounting concepts necessary for future studies." },
  { code: "ACC2202", name_en: "Financial Accounting II", name_ar: "المحاسبة المالية 2", credit_hours: 5, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting"], prerequisites: ["ACC2201"], description_en: "Building on previous studies in financial accounting, students expand their knowledge of fundamental accounting concepts involved in measuring and analyzing business transactions and reporting financial results. The coverage for course content builds upon topics from the first financial accounting course. Through a combination of practical exercises and the use of computer software, students’ progress in their understanding of vital accounting concepts necessary for future studies. Prerequisite(s): ACC2201" },
  { code: "ACC2209", name_en: "Financial Accounting III", name_ar: "المحاسبة المالية 3", credit_hours: 5, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting"], prerequisites: ["ACC2202"], description_en: "A thorough understanding of accounting concepts underlying business is critical in the field of accounting. The coverage for the course content builds upon topics from the first two financial accounting courses. The combination of practical exercises and the use of computer software create opportunities for students to practice the skills required for introductory accounting tasks. Prerequisite(s): ACC2202" },
  { code: "ACC2211", name_en: "Payroll and Compliance", name_ar: "الرواتب  والامتثال", credit_hours: 4, course_type: "lecture", language: "en", programs: ["diploma-accounting"], prerequisites: ["ACC2202"], description_en: "Payroll and statutory compliance reporting is mandatory for every business to adhere to. Students learn how to apply payroll legislation to calculate deductions, net pay, and remittances, and complete year-end payroll reporting. Students are introduced to the different types of requirements with which businesses are expected to comply, including GST/HST, QST, EHT and worker's compensation. Through a combination of theory and practical activities, students prepare these submissions and calculations by reading through relevant legislation and completing activities. Prerequisite(s): ACC2202" },
  { code: "ACC2214", name_en: "Financial Information for Marketing", name_ar: "المعلومات المالية للتسويق", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-marketing"], prerequisites: [], description_en: "Students are introduced to management accounting information used by the marketing manager to make financial decisions. Computer applications are used to illustrate problem-solving techniques." },
  { code: "ACC2233", name_en: "Management Accounting I", name_ar: "المحاسبة الإدارية 1", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting"], prerequisites: ["ACC2202"], description_en: "Businesses are faced with critical decisions daily; managerial accounting aids organizations in making well informed decisions that help the businesses to succeed. Students are introduced to the principles essential to an understanding of managerial accounting by focusing on the nature of costs and cost behaviors, and how they relate to and are reported in a manufacturing, merchandising and service business environment. Topics covered include job-order costing, process costing, volume-profit, variable costing, and activity-based costing. These managerial accounting concepts are explored through Excel-based lectures and discussions. Prerequisite(s): ACC2202" },
  { code: "ACC2234", name_en: "Management Accounting II", name_ar: "المحاسبة الإدارية 2", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting"], prerequisites: [], description_en: "Students continue to expand their knowledge of managerial accounting. Topics covered in the course include comprehensive corporate budgeting, standard costing, segment reporting, relevant costing, and capital budgeting. The current business focus on quality and business ethics is related to most topic areas. These managerial accounting concepts are explored through Excel-based lectures and discussions. Prerequisite(s): ACC2233 and ACC2343" },
  { code: "ACC2262", name_en: "Introduction to  Personal Taxation", name_ar: "الضرائب 1", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting"], prerequisites: ["ACC2202"], description_en: "Accurate completion of personal tax returns using current tax software is an essential employment related skill. Using a variety of methods including tax cases, lectures and internet research, students prepare a comprehensive personal Canadian tax return using a professional tax software program. Basic principles of tax planning and compliance with relevant tax legislation and regulations are stressed. It is strongly recommended that students use a Windows-based laptop (not a Mac). Prerequisite(s): ACC2202" },
  { code: "ACC2265", name_en: "Audit Principles and Business Issues", name_ar: "مبادىء التدقيق وقضايا الأعمال", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting"], prerequisites: ["ACC2209"], description_en: "Students are introduced to current business issues relevant to Canadian organizations and key auditing concepts that help in guiding business ethics and decisions. Topics discussed include the Canadian business environment and the current issues it faces, the need for greater ethical and responsible behavior in the light of recent business scandals, fraud and the need for internal controls, risk management and financial statement analysis, and the various types of audit functions and tools employed by financial statement auditors. Classroom lectures are enhanced by reading material on current and latest trends and using various tools to research information. Prerequisite(s): ACC2209" },
  { code: "ACC2343", name_en: "Spreadsheet Applications", name_ar: "تطبيقات جداول البيانات", credit_hours: 4, course_type: "lab", language: "bilingual", programs: ["diploma-accounting"], prerequisites: [], description_en: "Students enhance their knowledge of spreadsheets learned in BUS2301. Using Microsoft Excel, students explore some of the more advanced Excel features, such as financial functions, charts, logical functions, pivot tables, lists and look-up tables. These spreadsheet concepts are explored through Excel-based lectures and hybrid activities including learning resource applications. Prerequisite(s): ACC2201 and BUS2301" },
  { code: "ACC2385", name_en: "Accounting Software Applications", name_ar: "تطبيقات البرامج المحاسبية", credit_hours: 4, course_type: "lab", language: "bilingual", programs: ["diploma-accounting"], prerequisites: ["ACC2202"], description_en: "It is a workplace expectation that students are comfortable using accounting software on a day-to-day basis. Students gain practical experience using computerized accounting software to record transactions and prepare financial statements. Curriculum is delivered in lecture format and by hands-on completion of cases using accounting software. A Windows-based laptop (not a Mac) is strongly recommended. Prerequisite(s): ACC2202" },
  { code: "BUAC3005", name_en: "Intermediate Accounting", name_ar: "المحاسبة المتوسطة", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["bba-accounting"], prerequisites: [], description_en: "Students will study the Accounting Principles and the essential elements of preparing a financial statement. They will be able to discuss theoretical foundation of financial accounting, basic issues related to equity, dilutive securities and earning per share, accounting for leases, accounting changes and error analysis, statement of cash flow and full disclosure in Financial Reporting. Students will then be able to apply the International Financial Reporting Standards (IFRS) by using different skills to solve case problems such as solving skills, communication skills, and interpersonal skills. BUAC3050 Accounting for Government and Not for Profit Organization 3 Credits Students will be able to compare characteristics that distinguish governmental and non-governmental entities. They will apply key concepts and terms used in describing the government reporting entities. Students will understand the accounting principles, financial reporting and auditing requirements for government units and non-profit entities, such as accounting cycle, budgeting and fund accounting, and accounting for state and local governments, colleges and universities, and not-for-profit organizations. Students will be able to solve case problems by using different skills to solve case problems such as solving skills, communication skills, and interpersonal skills." },
  { code: "BUAC3050", name_en: "Accounting for Government and Not for Profit Organization", name_ar: "المحاسبة للمؤسسات الحكومية وغير الربحية", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["bba-accounting"], prerequisites: [], description_en: "Students will be able to compare characteristics that distinguish between governmental and non-governmental entities. They will apply key concepts and terms used in describing the government reporting entities. Students will understand the accounting principles, financial reporting and auditing requirements for government units and non-profit entities, such as accounting cycle, budgeting and fund accounting, and accounting for state and local governments, colleges and universities, and not-for-profit organizations. Students will be able to solve case problems by using different skills to solve case problems such as solving skills, communication skills, and interpersonal skills." },
  { code: "BUAC3100", name_en: "Principles of Financial Accounting", name_ar: "مبادىء المحاسبة المالية", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["bba-marketing"], prerequisites: [], description_en: "Students develop the ability to work effectively with their accountants and bookkeeper through their business launch and operations. Topics include balance sheets, income statements, journalizing in the general journal, general ledger and special journals, proper banking procedures, cash control protocols and government related employee payroll and tax requirements." },
  { code: "BUAC3120", name_en: "Managerial Accounting ​", name_ar: "المحاسبة الإدارية", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["bba-management"], prerequisites: [], description_en: "Students learn managerial accounting tools to help make decisions in a business environment. Students review and analyze managerial accounting practices of different industries. Students study topics which include relevant costs and revenues, budget development and analysis, capital budgeting and performance measurement tools. Students apply concepts learned by using cases and applied exercises." },
  { code: "BUAC3380", name_en: "Managerial Finance", name_ar: "التمويل الإداري", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["bba-marketing"], prerequisites: [], description_en: "Students are introduced to corporate finance and obtain an understanding of the role and function of financial management. Students learn financial ratio analysis, how to determine cash flows and time value of money. Students also learn how to value debt and equity investments, capital budgeting techniques, and cost of capital and capital structure." },
  { code: "BUAC4120", name_en: "Financial Statement Presentation and Analysis", name_ar: "عرض وتحليل البيانات المالية", credit_hours: 2, course_type: "lecture", language: "en", programs: ["bba-accounting"], prerequisites: [], description_en: "Students investigate financial statement presentation, including proper note disclosure appropriate for publication according to generally accepted accounting principles (GAAP) with an emphasis on International Financial Reporting Standards (IFRS). Students analyze and evaluate financial statements in the form of published annual reports, with special emphasis on different industry-specific presentations and disclosure styles. Students study differences in international accounting standards. Students prepare case analysis requiring integration of information and using both qualitative and quantitative analysis. Prerequisites: BUAC 3005" },
  { code: "BUAC4380", name_en: "Intermediate Corporate Finance", name_ar: "تمويل الشركات المتوسط", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["bba-accounting"], prerequisites: [], description_en: "Students describe, apply, and evaluate corporate finance techniques used in forecasting, financial planning, working capital management and dividend policy decisions. Students apply valuation techniques to more advanced business valuations. Students learn about derivative financial instruments, mergers and acquisitions and are introduced to international corporate finance." },
  { code: "BUAC4455", name_en: "Advanced Financial Accounting", name_ar: "المحاسبة المالية المتقدمة", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting"], prerequisites: [], description_en: "Students study current issues in financial reporting, intercorporate investments and business combinations, foreign operations, not-for-profit organizations, interim reports, segmented information, partnerships, and joint ventures. Students are required to undertake research projects where students will develop their skills to research a wide variety of resources. Students will review topics such as company accounting, disclosure of information and investment accounting standards. Prerequisites: BUAC 3005." },
  { code: "BUAC4720", name_en: "Cost Accounting", name_ar: "حساب التكلفة", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting"], prerequisites: [], description_en: "Students utilize advanced managerial accounting theories in planning and decision making in various business situations. Students assess overall business needs. Students design and evaluate integrative management accounting strategies through case analysis and projects. Prerequisites: BUAC 4455" },
  { code: "BUAC4780", name_en: "Advanced Corporate Finance", name_ar: "تمويل الشركات المتقدم", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting"], prerequisites: [], description_en: "Students will learn the advanced theoretical and applied treatment of major issues in Corporate Finance. The first part of the course is an in-depth exploration of advanced theories used to understand financial markets in the context of corporate borrowing and lending. While the second part of the course will focus on the real-world applications of corporate finance tools to address issues commonly faced by corporate managers, investors, and entrepreneurs. Each week, students will focus on a particular issue facing practitioners and explore individual case studies of problems such as capital budgeting, the design of optimal capital structures, and the valuations of start-ups, mergers, and private equity buyouts. We will also discuss the relevance of these tools for careers in finance, consulting, and other sectors. Prerequisites: BUAC 4380" },
  { code: "BUAD3090", name_en: "Business Law", name_ar: "قانون اللعمل", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting", "bba-marketing"], prerequisites: [], description_en: "A review of the meaning, sources, and administration of commercial law and ethical framework of business. Students will be able to examine the applicable law with reference to business situations." },
  { code: "BUAD3091", name_en: "Employment Law", name_ar: "قانون التوظيف", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-management"], prerequisites: [], description_en: "Students will be provided with an opportunity to engage deeply with organizational structures. It uses a range of critical issues that are related to employment relationship through several legal and management skills. This module combines the legal concepts and the practical applications of the law with a contextual understanding of employment law. This module introduces two main themes; firstly, it provides students with a good understanding of different aspects of employment law theories. Secondly, the module presents an analysis of the formation employment contract, termination of the agreement, and parties’ duties and rights under the employment contract. Students will study individual employment contracts, the distinction between employment and individual contracting, the scope of employment law, and the duties and rights of the parties. Furthermore, students will study the requirements of the social insurance authority in Kuwait, financing, and management of social security, and how to compensate the insured individuals as part of their pensions. The module will typically allow students to engage with different aspects arising from the employment relationship through class discussion and problem-solving methods according to the applicable law. Prerequisites: BUHR 4120" },
  { code: "BUCO3005", name_en: "Management Information Systems", name_ar: "نظم المعلومات الإدارية", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["bba-marketing", "bba-management"], prerequisites: [], description_en: "Students will be introduced to management information systems and the importance of systems in achieving organizational goals. Topics include how to develop and maintain information systems to gain competitive advantage, to solve business problems, and to improve decision making. The role of information systems and systems development in business operations is also discussed. This course is designed to support the College of Business curriculum and satisfies the general degree requirement for computer literacy for business majors." },
  { code: "BUCO3160", name_en: "Information Technology for Business", name_ar: "تكنولوجيا المعلومات للأعمال", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["bba-marketing", "bba-management"], prerequisites: ["BUCO3005"], description_en: "Students will be absorbing the topics of the curriculum in business information technology in a way that provides them with expertise in the quantitative and technological aspects of management, specifically including the extensive use of computers for solving business problems and making managerial decisions. Prerequisite(s): BUCO3005" },
  { code: "BUEN3025", name_en: "Enterprise Development and Business Planning", name_ar: "تطوير المشاريع وخطة العمل", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["bba-marketing"], prerequisites: [], description_en: "Students utilize their knowledge of business principles to develop business plans, form companies, and actively manage their companies via a business simulation. Students apply several key concepts relating to the major functional areas of a business and make realistic management decisions in a simulated competitive environment." },
  { code: "BUEN3100", name_en: "Business Analysis and Decision Making", name_ar: "التحليل التجاري واتخاذ القرار", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting", "bba-marketing", "bba-management"], prerequisites: [], description_en: "Students apply previously learned analytical tools to address a wide range of organizational issues. They develop and assess options based on sound strategic analysis and research. Students recommend solutions supported by quantitative and qualitative rationale. They develop their problem solving, judgment, analysis, evaluation and decision-making skills through case analyses and applied exercises. Students are required to undertake both individual and group work, drawing from the full range of business courses completed thus far. Prerequisites: BUMT3030" },
  { code: "BUEN3230", name_en: "Supply Chain & Logistics Management", name_ar: "إدارة سلسلة التوريد والخدمات اللوجستية", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-marketing", "bba-management"], prerequisites: [], description_en: "Students learn how to design, manage, and assess end-to-end supply chains and logistics in manufacturing as well as in service industries. They study the latest concepts and formal tools for planning and auditing supply chains and logistics. Included in this study are the choices of the most appropriate locations, transportation systems and facilities. Students practice creating value-adding systems, eliminating waste, and developing sustainable supply chains and logistics networks to generate a significant positive impact to the organization's triple bottom line. They apply their knowledge and skills in exercises and projects involving real-world or simulated organizations. Prerequisites: BUEN3100" },
  { code: "BUEN4150", name_en: "Management of Innovation", name_ar: "إدارة الابتكار", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-management"], prerequisites: [], description_en: "Students learn how to manage innovation using formal processes, frameworks, and tools. They study the latest innovation management approaches in the areas of design of innovation strategies. Students study stimulation of creativity and harnessing of technologies, development of goods, services and processes, business model innovation, and measurement of innovation performance. They are given the opportunity to examine successful innovation management practices in organizations of all types and sizes. Students apply their knowledge and skills in exercises and projects involving real-world or simulated organizations." },
  { code: "BUEN4200", name_en: "Business Strategy", name_ar: "استراتجية العمل", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting", "bba-marketing", "bba-management"], prerequisites: [], description_en: "Students focus on the conceptual and practical aspects of strategic decision making in business. They learn how to formulate strategies, evaluate strategic alternatives using financial and non-financial criteria, implement strategies and manage strategic change in organizations through a series of case analyses, business exercises and current examples from industry. Prerequisites: BUEN 3100, BUAC 3380, GEEC 3250" },
  { code: "BUEN4250", name_en: "Entrepreneurial Leadership Practicum I", name_ar: "التدريب العملي لقيادة ريادة الأعمال 1", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-marketing", "bba-management"], prerequisites: [], description_en: "Students will be introduced to understand the requirements of a client organization in terms of management and design. They will gradually be understanding the base of project development and business partnership. The scope of the course includes special business skills and concepts. Prerequisites: BUEN3100" },
  { code: "BUEN4251", name_en: "Entrepreneurial Leadership Practicum II", name_ar: "التدريب العملي لقيادة ريادة الأعمال 2", credit_hours: 2, course_type: "lecture", language: "en", programs: ["bba-marketing", "bba-management"], prerequisites: [], description_en: "Students learn how to manage, design, prepare and present a comprehensive project that will meet the requirements of a client organization. They develop and complete a significant project in partnership with businesses or as part of developing an entrepreneurial endeavour. Students gain the opportunity to practice the integration of business skills and concepts. Prerequisites: BUEN 4250" },
  { code: "BUHR4120", name_en: "HR Management for Entrepreneurs", name_ar: "إدارة الموارد البشرية لرواد الأعمال", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["bba-marketing", "bba-management"], prerequisites: [], description_en: "Students acquire an in-depth understanding of the human resource (HR) management needed to enable an organization to face changes and challenges. Students engage in research, present key findings, and engage in best practice dialogues around a variety of key human resource management concepts, including legal and diversity issues, employee acquisition and deployment, performance management, career development, employee compensation and rewards, employee communications and discipline, union- management relations, occupational health and safety, and international human resource management." },
  { code: "BUMG3015", name_en: "Organizational Behaviour", name_ar: "السلوك التنظيمي", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting"], prerequisites: [], description_en: "Students learn how the behaviour of individuals and groups in work environments affect organizational performance. Topics include individual attributes, motivation theories and strategies, group dynamics, teamwork, organizational structure, job design, leadership, organizational culture and politics, communication, conflict, stress and change management. Special emphasis is placed on diversity, cross cultural issues, and ethical conduct in organizations." },
  { code: "BUMG3105", name_en: "Operations Management", name_ar: "إدارة العمليات", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting", "bba-marketing", "bba-management"], prerequisites: [], description_en: "Students learn and practice the fundamental design and implementation tools and techniques used in Operations Management (OM). They are exposed to leading practices employed by entrepreneurs and managers in organizations of all sizes, both in manufacturing and service industries, particularly in small and medium-sized enterprises. Students apply the theoretical qualitative and quantitative approaches to solve practical problems through exercises, case analyses, and a group term project involving work with real-world or simulated organizations. Prerequisites: GEEC 3150, BUMT 3030, BUMG3015, BUMK3099" },
  { code: "BUMG3110", name_en: "Advanced Organizational Behaviour", name_ar: "السلوك التنظيمي المتقدم", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-marketing", "bba-management"], prerequisites: [], description_en: "Students complete a diagnosis of an organizational setting for the purposes of managing change, improving performance, and increasing organizational effectiveness. Students use their diagnosis to develop a portfolio that includes activity management, personal management, conflict and stress management, values, attitudes, group dynamics, leadership and team development, corporate politics, and business negotiations. Prerequisites: BUHR4120" },
  { code: "BUMK3099", name_en: "Introduction to Marketing", name_ar: "تعريف التسويق", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting"], prerequisites: [], description_en: "Students learn the fundamentals of marketing and explore the relationships between companies, their customers and their competition. They examine concepts that are integral to the field of marketing including marketing environment, customer behaviour, marketing research, product analysis, distribution, pricing strategies and promotion. They apply these concepts in solving marketing problems." },
  { code: "BUMT3030", name_en: "Business Statistics", name_ar: "الإحصاءات التجارية", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting", "bba-management"], prerequisites: [], description_en: "Students learn statistical concepts, methods and procedures used in business, including descriptive statistics--graphics and numerical presentations, probability theory, sampling, estimation, hypothesis testing and linear regression. The use of statistical software applications forms part of the course. Students are expected to know, or to acquire on their own, basic Excel skills." },
  { code: "BUS2301", name_en: "Business Computer Applications", name_ar: "تطبيقات الكمبيوتر الإدارية", credit_hours: 3, course_type: "lecture_lab", language: "bilingual", programs: ["diploma-accounting", "diploma-marketing", "diploma-management"], prerequisites: [], description_en: "The knowledge gained in this course provides students with a solid foundation for future learning in other studies, and in business. Students learn a variety of tasks in Windows file management. Students also learn tasks and produce assignments in Microsoft Office for PC. Web based software running computer-based simulations and assessments are used to support and enrich the learning experience. It is strongly recommended that students use a PC. Mac students may be required to install and learn additional software to successfully complete the course." },
  { code: "CSIT3014", name_en: "Discrtete Mathematics for Information Technology", name_ar: "الرياضيات لتكنولوجيا المعلومات", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["basc-cs"], prerequisites: [], description_en: "Students learn the basic mathematical concepts which form the foundations of computing systems. They are able to apply mathematical logic and methods to software development. They learn the principles and applications of discrete mathematics, data organization and data representation." },
  { code: "CSIT3111", name_en: "Advanced Networking Technologies", name_ar: "تقنيات الشبكات المتقدمة", credit_hours: 3, course_type: "lecture_lab", language: "ar", programs: ["basc-cs"], prerequisites: [], description_en: "Students learn the operation details of routers and switches in small to medium size computer networks. They acquire skills for configuring and troubleshooting routers and switches. They also develop skills in resolving common issues which exist when routing between different protocols." },
  { code: "CSIT3115", name_en: "Data Structure", name_ar: "هيكل البيانات", credit_hours: 3, course_type: "lecture_lab", language: "bilingual", programs: ["basc-cs"], prerequisites: [], description_en: "Students learn the data structures and associated algorithms commonly used in system development. They learn Application of Linked Lists, Stacks, Queues, Binary Trees, Balanced Trees, Searching of Trees, Lists, Inverted Lists, Multi-lists, and Graphs. These are the fundamental tools available for contemporary programming languages for the implementation of complex algorithms." },
  { code: "CSIT3211", name_en: "Foundations of Computer Security ​", name_ar: "أسس أمن الكمبيوتر", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["basc-cs"], prerequisites: [], description_en: "Students learn fundamental concepts, theories, methodologies and techniques of computer and network security. Students gain an understanding of the importance of security within and between organizations, including the ongoing threats and vulnerabilities on networks. In this course the significance of being ethical is emphasized. It covers the aspects of systems security from the perspective of providing security mechanisms for protecting networks. Students learn several software tools and techniques related to computer security using mechanisms such as cryptographic systems, authentication, and access control methods. Different types of network and computer attacks are studied. Tools to discover network designs, functionality, resources, and vulnerabilities are introduced." },
  { code: "CSIT3216", name_en: "Server Operating Systems ​", name_ar: "انظمة تشغيل السيرفر", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["basc-cs"], prerequisites: [], description_en: "Students learn the principles, techniques and strategies used in planning, installing, testing, and administering a server operating system. Students learn to create and manage user accounts using Active Directory, and to install and configure server roles including Dynamic Host Configuration Protocol (DHCP), Domain Name System (DNS), printer server, Internet Information Services (IIS), and Virtual Private Network (VPN). Students are required to plan, design, and install an application server to simulate real-world scenarios. Students gain hands-on experience installing, troubleshooting, fine-tuning, and administering a server operating system." },
  { code: "CSIT3225", name_en: "Introduction to Programming with Python ​", name_ar: "مقدمة في البرمجة باستخدام بايثون", credit_hours: 3, course_type: "lecture_lab", language: "bilingual", programs: ["basc-cs"], prerequisites: [], description_en: "Students will learn the Introduction to programming basics (what it is and how it works), binary computation, problem-solving methods, and algorithm development. Includes procedural and data abstractions, program design, debugging, testing, and documentation. Covers data types, control structures, functions, parameter passing, library functions, arrays, inheritance, and object-oriented design. Laboratory exercises in Python." },
  { code: "CSIT3235", name_en: "Software Quality Assurance ​", name_ar: "ضمان جودة البرمجيات", credit_hours: 3, course_type: "lecture_lab", language: "bilingual", programs: ["basc-cs"], prerequisites: [], description_en: "Students will learn the difference between Software Quality Assurance (SQA) and Software Quality Control (SQC). Also, they will study the reasons for SQA failures and factors critical to success of SQA in IS development in addition to the six Proactive Software Quality Assurance™ functions that SQA should perform and the proactive methods for more effectively reviewing requirements and designs. Additionally, students will be applying risk analysis, reusable testware, and metrics to perform more thorough testing in less time as well as understanding the measuring system quality and SQA/Testing effectiveness." },
  { code: "CSIT3271", name_en: "System Security", name_ar: "أمن الأنظمة", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["basc-cs"], prerequisites: ["CSIT3211"], description_en: "Students learn fundamental concepts, theories, and practical skills of system security. This course covers vulnerabilities of operating systems and covers how systems can be penetrated. Students learn digital data integrity to ensure the data is unchanged. It also covers data security, network security, web server security and web application security. Tools to discover network designs, functionality, resources, and vulnerabilities are introduced. Security mechanisms for protecting networks are evaluated and security planning is considered. In this course the significance of being ethical is emphasized. Prerequisite(s): CSIT 3211" },
  { code: "CSIT3280", name_en: "Information Technology Project Management", name_ar: "إدارة مشاريع تكنولوجيا المعلومات", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["basc-cs"], prerequisites: [], description_en: "Students learn topics in Information Technology (IT) project management. They examine various issues related to the development and implementation of complex information systems. Students explore the use of new technologies in IT project management and use a project management software tool to complete assignments, case studies and a term project." },
  { code: "CSIT3345", name_en: "Advanced Web Application Development", name_ar: "تطوير تطبيقات الويب المتقدمة", credit_hours: 3, course_type: "lecture_lab", language: "bilingual", programs: ["basc-cs"], prerequisites: [], description_en: "Students learn PHP and MySQL and use them to develop dynamic, secure, and commercially usable websites. They learn the basics of PHP and MySQL and learn how to access the data in a MySQL database through the Web using PHP. Students are able to develop shopping carts and Web forums using PHP and MySQL." },
  { code: "CSIT4105", name_en: "Search Engine Principles", name_ar: "مبادىء محرك البحث", credit_hours: 3, course_type: "lecture_lab", language: "bilingual", programs: ["basc-cs"], prerequisites: [], description_en: "Students learn the principles of search engines and information retrieval. Information filtering and retrieval drives some of the world's most successful and high-tech businesses. Students learn various methods of search engine optimization (SEO), ranging from theory to implementation. Students learn how to use tools and methods to perform searches and utilize results effectively. They also learn how large data sources such as social media affects information retrieval. Co-requisites: CSIT 3345." },
  { code: "CSIT4125", name_en: "Website & Cloud Security", name_ar: "أمن المواقع والكلاود", credit_hours: 3, course_type: "lecture", language: "en", programs: ["basc-cs"], prerequisites: ["CSIT3211"], description_en: "Students learn the core mechanisms and tools for Web and cloud security. They learn the principles of Web attacks on authentication, users, application servers, data stores, back-end components, application logic and bypassing client-side controls. They learn how to discover and prevent Web security flaws during Web application development and measures to improve Web security. They also learn how to identify and resolve security issues specific to public and private clouds. Prerequisite(s): CSIT 3211" },
  { code: "CSIT4190", name_en: "Integration Project I", name_ar: "مشروع التكامل 1", credit_hours: 3, course_type: "lecture_lab", language: "bilingual", programs: ["basc-cs"], prerequisites: [], description_en: "Students conduct extensive literature reviews and research for projects originating from faculty or the stakeholders from the industry or local communities. Students carry out detailed project designs and complete the overall project design documentation in this capstone course. They report on the design results through presentations that are open to all faculty and students in the department and industry sponsors. Students apply in great depth and breadth the system, hardware, software, and project management knowledge they learned in the program to accomplish the tasks of the project." },
  { code: "CSIT4235", name_en: "Special Topics in Web & Mobile App Development", name_ar: "موضوعات في تطوير تطبيقات الويب والهواتف المحمولة", credit_hours: 2, course_type: "lecture", language: "bilingual", programs: ["basc-cs"], prerequisites: [], description_en: "This course offers selected topics on web and mobile application development. The topics are based on emerging industrial technologies, including but not limited to application design, service integration, system development, and application deployment on both web and mobile platforms. Students learn novel concepts of web and mobile technologies required by the IT industry. Prerequisites: CSIT 3345" },
  { code: "CSIT4290", name_en: "Integration Project II", name_ar: "مشروع التكامل 2", credit_hours: 3, course_type: "lecture", language: "en", programs: ["basc-cs"], prerequisites: [], description_en: "Students implement the project designs they produced in the course CSIT 4190 (Integration Project I) using suitable software tools and selected hardware. They test and debug the project implementations and generate the final system prototype and project documentation. They report and demonstrate the final project results through presentations which are open to all faculty and students in the department, as well as industrial sponsors. Prerequisite: CSIT 4190" },
  { code: "CSIT4330", name_en: "Data Warehousing and Data Mining", name_ar: "استخراج وتخزين البيانات", credit_hours: 3, course_type: "lecture", language: "en", programs: ["basc-cs"], prerequisites: [], description_en: "Students examine the problems caused by having too much information and the methods, processes, and tools for extracting useful information from multidimensional databases and data marts stored on different system platforms. They also acquire the techniques for defining, selecting, implementing, and evaluating data warehousing and data mining solutions for businesses." },
  { code: "CST2234", name_en: "Systems Analysis & Design", name_ar: "تحليل وتصميم النظم", credit_hours: 4, course_type: "lecture", language: "en", programs: ["diploma-cp"], prerequisites: ["CST8215", "CST8284"], description_en: "Guided by industry standard software engineering methodologies, students gain hands-on experience with case studies used to develop systems from inception through elaboration, construction and transition phases. Object-oriented design, modeling tools and techniques are used to produce system specifications. Project management principles are also used within team-developed projects. Software methodologies discussed include the systems development life cycle (SDLC), agile approach, rational unified process (RUP)and rapid application development (RAD). Prerequisite(s): CST8215, CST8284." },
  { code: "CST2335", name_en: "Mobile Graphical Interface Programming", name_ar: "برمجة الواجهة الرسومية للجوال", credit_hours: 4, course_type: "lecture_lab", language: "en", programs: ["diploma-cp"], prerequisites: ["CST8215", "CST8284"], description_en: "Mobile Graphical Interface Programming Development of graphical user interfaces (GUI) in a mobile android environment is explored. Learn to construct mobile GUI applications using the latest Android tools and applying the latest Android best practices. Prerequisite(s): CST8215, CST8284." },
  { code: "CST2355", name_en: "Database Systems", name_ar: "انظمة قواعد البيانات", credit_hours: 4, course_type: "lecture_lab", language: "bilingual", programs: ["diploma-cp"], prerequisites: ["CST8215"], description_en: "Acquire practical experience using market-leading object-relational database management systems like Oracle and MySQL. Obtain hands-on experience with advanced engineering modeling tools along with SQL, SQL scripts and programming with Oracle's PL/SQL blocks. Database concepts covered include advanced SQL, case structures, rollup and cube operations, metadata manipulation, data storage and retrieval, security and transaction control and data warehousing. Open-source database software is also explored. Prerequisite(s): CST8215." },
  { code: "CST8101", name_en: "Computer Essentials", name_ar: "اساسيات الكمبيوتر", credit_hours: 4, course_type: "lecture_lab", language: "bilingual", programs: ["diploma-cp"], prerequisites: [], description_en: "Maintaining a computer, using operating system and productivity software, and expressing related environmental and sustainability concerns, is an important part of working with Information Technology. Students explain computer hardware, and use operating system software to maintain, utilize, and secure a computer. Students practice the use of spreadsheet software to solve problems, use formulas, and visualize data with charts. Students discuss computer hardware and software with regards to financial and environmental sustainability. Theory is reinforced with application by means of practical laboratory assessments, including using virtualization software to install guest operating systems onto a host computer" },
  { code: "CST8102", name_en: "Operating System Fundamentals (GNU/Linux)", name_ar: "اساسيات نظام التشغيل  (GNU/Linux)", credit_hours: 4, course_type: "lecture_lab", language: "bilingual", programs: ["diploma-cp"], prerequisites: ["CST8101"], description_en: "Learn the basic concepts and components of Operating Systems (OS), and how they function and interact with hardware and software components. Explore the details of operating system structures, process management, storage management, installation, configuration, and administration both in theory and through practical assignments based on the GNU/Linux operating system. Lab exercises are designed to demonstrate how to implement the theory by developing skills using the powerful GNU/Linux command-line tools and utilities. Prerequisite(s): CST8101" },
  { code: "CST8109", name_en: "Network Programming", name_ar: "برمجة الشبكات", credit_hours: 4, course_type: "lecture_lab", language: "en", programs: ["diploma-cp"], prerequisites: ["CST8116", "MAT8001"], description_en: "Software programming in today's environment requires detailed knowledge of the underlying network topology, its implementation and programming support functions. Gaining an appreciation and perspective of this technology is imperative to developing good network programming applications. Students explore topics including the basic structure, design and layered communications models, with an emphasis on data communications, TCP/IP protocol suite, socket programming and multi-threading concepts. Labs include practical exercises in basic networking and using socket programming, along with multi-threading, in an environment rich with common networking tools for diagnosing and troubleshooting typical network programming problems. Prerequisite(s): CST8116, MAT8001." },
  { code: "CST8116", name_en: "Intro to Computer Programming", name_ar: "مقدمة الى برمجة الكمبيوتر", credit_hours: 4, course_type: "lab", language: "ar", programs: ["diploma-cp"], prerequisites: [], description_en: "Students receive an introduction to computer programming with emphasis on problem analysis and design, using algorithms, pseudocode, flowcharts, UML class diagrams and testing, with the Java programming language used as a means to implement problem solution designs. Instruction in the Java programming language is provided including an introduction to object-oriented programming, sequential structure, selection structures, repetition structures, variables, constants, methods, constructors, one-dimensional arrays, classes, objects, encapsulation, abstraction, inputs, outputs, coding conventions and documentation. Theory is reinforced with application by means of practical laboratory assessments." },
  { code: "CST8117", name_en: "Cross-Platform Web Design", name_ar: null, credit_hours: 4, course_type: "lecture_lab", language: "ar", programs: ["diploma-iawd"], prerequisites: [], description_en: "Technologies on the web evolve quickly. Every year brings new devices and with them new capabilities. These devices present many challenges and opportunities to web developers. Fundamentals of web development using hypertext markup language (HTML), and cascading style sheets (CSS) are reviewed, with a focus on developing responsive and mobile websites. Multiple IDEs are introduced and used to complete hands-on projects." },
  { code: "CST8209", name_en: "Web Programming I", name_ar: null, credit_hours: 4, course_type: "lab", language: "ar", programs: ["diploma-iawd"], prerequisites: [], description_en: "Emphasis is on client-side browser scripting using JavaScript. Students focus on the theory behind client-side web scripting and how to manage interactive sites that use JavaScript to generate and manipulate a page's HTML and CSS. Topics include object detection, DOM manipulation, timers and animation, event handling, functions, jQuery introduction, form validation, timers and simple animations." },
  { code: "CST8215", name_en: "Introduction to Database", name_ar: "تعريف قاعدة البيانات", credit_hours: 5, course_type: "lab", language: "bilingual", programs: ["diploma-cp"], prerequisites: [], description_en: "Communication remains an essential skill sought by employers, regardless of discipline or field of study. Using a practical, vocation-oriented approach, students focus on meeting the requirements of effective communication. Through a combination of lectures, exercises, and independent learning, students practice writing, speaking, reading, listening, locating and documenting information and using technology to communicate professionally. Students develop and strengthen communication skills that contribute to success in both educational and workplace environments." },
  { code: "CST8250", name_en: "Database Design and Administration", name_ar: null, credit_hours: 5, course_type: "lab", language: "ar", programs: ["diploma-iawd"], prerequisites: [], description_en: "A solid theoretical and practical understanding of database design and database administration is provided. The material is dealt with from the point of view of the user, the database designer and the database administrator. Topics to be covered include relational database design (e.g., data modelling, normalization, ER diagrams, integrity constraints) and database administration (e.g., user management, backups and restores, database security). Prerequisite: CST8260." },
  { code: "CST8253", name_en: "Web Programming II", name_ar: null, credit_hours: 4, course_type: "lecture_lab", language: "ar", programs: ["diploma-iawd"], prerequisites: ["CST8209"], description_en: "Through the study of C# and ASP.net, students learn the concepts of object-oriented programming as applied to the design, the development and the debugging of ASP.net web. Object-oriented concepts, such as encapsulation, inheritance, abstraction and polymorphism are covered and reinforced with practical applications. The course also continues the development of Web Programming concepts by examining and using HTML form elements, web server controls, the ASP.NET Page class, its inherent Page, Request, Response and Cookies objects. Prerequisite(s): CST8209." },
  { code: "CST8254", name_en: "Network Operating Systems", name_ar: null, credit_hours: 5, course_type: "lecture_lab", language: "ar", programs: ["diploma-iawd"], prerequisites: [], description_en: "Students are introduced to the concepts behind implementing network operating systems in a multiple user, computer and Internet Protocol (IP) networked environment. Topics include managing and updating user accounts, access rights to files and directories, Transmission Control Protocol/Internet Protocol (TCP/IP) and TCP/IP services: Domain Name System (DNS), Hyper Text Transfer Protocol (HTTP/HTTPS) and File Transfer Protocol (FTP/SFTP). Theory and practical lab assignments are reinforced to install and configure a network operating system and the services mentioned. Prerequisite(s): CST8279 and MAT8001." },
  { code: "CST8256", name_en: "Web Programming Languages I", name_ar: null, credit_hours: 5, course_type: "lab", language: "bilingual", programs: ["diploma-iawd"], prerequisites: [], description_en: "Emphasis is placed on ways of moving data between web pages and databases using the .NET platform: C#, ASP.NET, (as well as ASP.NET Core), Microsoft Entity (as well as Microsoft Entity Framework core) and the .NET Framework (as well as .NET Framework core). Students focus on how web applications can interact with databases through Entity Frame or other technologies. Server-side methods and the advantages of multi-tiered and MVC (Model View Controller) application architecture are explored. Prerequisite(s): CST8253 and CST8260." },
  { code: "CST8257", name_en: "Web Applications Development", name_ar: null, credit_hours: 5, course_type: "lecture_lab", language: "bilingual", programs: ["diploma-iawd"], prerequisites: [], description_en: "Students are introduced to PHP and how this technology is used to create dynamic server-side web applications. Students learn how to build database-driven Web applications using PHP. Students learn techniques to access and process data, manage state information, upload and download files, interact with the file system and manipulate pictures through the study of examples. The course concludes with a mini project to develop a social media network with emphasis on sharing and managing picture albums. Prerequisite(s): CST8209 and CST8260." },
  { code: "CST8258", name_en: "Web Project Management", name_ar: null, credit_hours: 3, course_type: "lecture_lab", language: "bilingual", programs: ["diploma-iawd"], prerequisites: [], description_en: "This course introduces students to the software engineering process. System engineering, design, software quality assurance and testing are explored in detail. The course consists of lectures, case studies and practical lab group work. Project teams are provided with the opportunity to apply sound software engineering principles in the scoping and analysis of web-related projects. Students must produce appropriate documentation to support the project progression to the fourth level Project course. Prerequisite: CST8253." },
  { code: "CST8259", name_en: "Web Programming Languages II", name_ar: null, credit_hours: 5, course_type: "lab", language: "bilingual", programs: ["diploma-iawd"], prerequisites: ["CST8256"], description_en: "The concepts and use of high-level tools and current web programming languages used in web development, such as XML and JSON, Content Management Systems Web Services and JavaScript frameworks are addressed. Prerequisite(s): CST8256, CST8257 and CST8258." },
  { code: "CST8260", name_en: "Database System and Concepts", name_ar: null, credit_hours: 4, course_type: "lab", language: "ar", programs: ["diploma-iawd"], prerequisites: [], description_en: "A solid theoretical and practical understanding of database systems is provided. Topics covered include relational database design, data definition and manipulation using the Structured Query Language (SQL). Participants practice designing a database and extracting information from a database using SQL." },
  { code: "CST8265", name_en: "Web Security Basics", name_ar: null, credit_hours: 5, course_type: "lecture_lab", language: "bilingual", programs: ["diploma-iawd"], prerequisites: ["CST8256"], description_en: "Students explore how to secure websites and web applications. Tools and techniques for understanding basic web environment security and web application security are also explored. Common web application vulnerabilities and the mechanisms/tools to detect and prevent them are investigated. This may include such things as encryption, secure socket layers (SSL), authentication and authorization. Prerequisite(s): CST8256, CST8257 and CST8258." },
  { code: "CST8268", name_en: "Project", name_ar: null, credit_hours: 4, course_type: "lecture_lab", language: "bilingual", programs: ["diploma-iawd"], prerequisites: [], description_en: "Students apply sound software engineering principles in the design and implementation of a major web-related project. Students work in teams under the direction of a staff advisor. The projects undertaken are conceived either internally (by the College) or externally (local industry or organizations). In the case of external projects, industry professionals act as customers. Students must produce appropriate documentation to support the project progression. A formal project presentation to peers, faculty, staff and invited guests is required at the end of the course. Prerequisite(s): CST8257 and CST8258." },
  { code: "CST8276", name_en: "Advanced Database Topics", name_ar: "موضوعات قواعد البيانات المتقدمة", credit_hours: 4, course_type: "lab", language: "en", programs: ["diploma-cp"], prerequisites: ["CST2355", "CST8109"], description_en: "Teams and individuals explore advanced database topics: database administration (using Oracle), data governance, globalization, security and advances in database technology. Topic coverage includes business intelligence, data warehouses, data visualization and big data. Database administration tasks requiring knowledge of database architecture are examined: security, performance, database distribution, database sharing, backup and recovery. Prerequisite(s): CST2355, CST8109." },
  { code: "CST8277", name_en: "Enterprise Application Programming", name_ar: "برمجة تطبيقات المؤسسات", credit_hours: 4, course_type: "lab", language: "en", programs: ["diploma-cp"], prerequisites: ["CST8109", "CST8288"], description_en: "With a focus on the IT Enterprise, students are introduced to the application enterprise environment using and extending the technologies learned in previous courses. Topics studied may include the Java enterprise environment (J2EE), the Microsoft .NET environment, Enterprise Android programming, cloud computing, security and the corporate database repository. Prerequisite(s): CST8288, CST8109." },
  { code: "CST8279", name_en: "Introduction Computer Programming Using Python", name_ar: null, credit_hours: 5, course_type: "lab", language: "ar", programs: ["diploma-iawd"], prerequisites: [], description_en: "Emphasis is on principles of software development, style and testing. Students learn the basics of robust computer programming, with emphasis on correctness, structure, style and documentation using Python. Theory is reinforced with application by means of practical laboratory assignments." },
  { code: "CST8283", name_en: "Business Programming", name_ar: "برمجة الأعمال التجارية", credit_hours: 4, course_type: "lab", language: "bilingual", programs: ["diploma-cp"], prerequisites: ["CST8116"], description_en: "Create COBOL programs in a business environment using structured methodology in the latest visual programming environment. Topics include output design; logic design tools; structured, top-down and modular coding; testing and debugging; and documentation. The programs include interactive, file-based, and database processing of data related to business problems. Arrays, indexed files, database access and sub-programs are included. Prerequisite(s): CST8116." },
  { code: "CST8284", name_en: "Object-Oriented Programming (JAVA)", name_ar: "البرمجة الشيئية (JAVA)", credit_hours: 4, course_type: "lecture_lab", language: "bilingual", programs: ["diploma-cp"], prerequisites: ["CST8116"], description_en: "Learn object-oriented programming methodology using the Java programming language. Object-oriented concepts, such as encapsulation, inheritance, abstraction and polymorphism are covered and reinforced with practical applications. Prerequisite(s): CST8116." },
  { code: "CST8285", name_en: "Web Programming", name_ar: "برمجة الويب", credit_hours: 4, course_type: "lab", language: "bilingual", programs: ["diploma-cp"], prerequisites: ["CST8116"], description_en: "Learn the basics of web programming, website design and implementation. JavaScript, HTML5, and PHP are used to explore web-based solutions to problems of increasing interactivity and complexity. Lectures are reinforced by practical assignments that encourage students to construct and maintain their own websites. Prerequisite(s): CST8116." },
  { code: "CST8288", name_en: "Object-Oriented Programming with Design Patterns", name_ar: "البرمجة الشيئية مع انماط التصميم", credit_hours: 4, course_type: "lab", language: "en", programs: ["diploma-cp"], prerequisites: ["CST8215", "CST8284"], description_en: "Implement the best practices of object-oriented program development with software design patterns. Apply UML program specifications in the Java programming language. Use embedded SQL through JDBC for developing and using \"data access objects\". Course topics include refactoring, domain modelling, JDBC and multithreaded servlet programming. Students develop proficiency in creating, testing, debugging, deploying and documenting programs and servlets through practical application. Prerequisite(s): CST8215, CST8284." },
  { code: "CST8300", name_en: "Achieving Success in Changing Environments", name_ar: "تحقيق النجاح في البيئات المتغيرة", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["diploma-cp", "diploma-iawd"], prerequisites: [], description_en: "Rapid changes in technology have created personal and employment choices that challenge each of us to find our place as contributing citizens in the emerging society. Life in the 21st century presents significant opportunities, but it also creates potential hazards and ethical problems that demand responsible solutions. Students explore the possibilities ahead, assess their own aptitudes and strengths, and apply critical thinking and decision-making tools to help resolve some of the important issues in our complex society with its competing interests." },
  { code: "CST8318", name_en: "Graphics Technologies", name_ar: null, credit_hours: 3, course_type: "lab", language: "ar", programs: ["diploma-iawd"], prerequisites: [], description_en: "Students are introduced to graphics and illustration programs in the computer environment. Students also learn skills and production techniques which help to design effective interfaces for websites, mobile websites and mobile applications. Focus is placed on hands-on learning of software, such as Adobe Photoshop and Illustrator. Basic design concepts are covered within the context of becoming productive with the software packages." },
  { code: "CST8325", name_en: "Current Trends in Web Application Development", name_ar: null, credit_hours: 3, course_type: "lab", language: "bilingual", programs: ["diploma-iawd"], prerequisites: ["CST8256"], description_en: "The field of web development is dynamic and constantly changing with new tools, workflows and best practices for constructing usable applications. Students explore current trends in Web Application Development through guest speakers' presentations, case studies and hands-on exercises. Topics like eCommerce, eGovernment, eHR, Development frameworks and Content Management Systems are explored. Prerequisite(s): CST8256, CST8257 and CST8258." },
  { code: "CST8333", name_en: "Programming Language Research Project", name_ar: "مشروع بحث لغة البرمجة", credit_hours: 4, course_type: "lecture_lab", language: "en", programs: ["diploma-cp"], prerequisites: ["CST8284"], description_en: "Learning a new programming language or framework on your own is a challenge faced by programmers on the job as part of their career. Students explore this process of self-study by applying project planning, applied research, testing, and implementation of basic and advanced concepts appropriate to the language or framework under study. Students develop major milestones and deliverables culminating in a project and reflective summary submission. Prerequisite(s): CST8284." },
  { code: "CST8334", name_en: "Software Development Project", name_ar: "مشروع تطوير البرمجيات", credit_hours: 4, course_type: "lecture_lab", language: "bilingual", programs: ["diploma-cp"], prerequisites: ["CST2234", "CST2235", "CST8109", "CST8285", "CST8288"], description_en: "Following the agile software engineering methodology, teams work with clients to analyze business needs, determine computer system requirements, model system designs, build prototypes, test code and deliver final products. In some cases, the industry contacts are supplied through the Algonquin College office of Applied Research and Innovation. Project management techniques are used to monitor progress and organize tasks. Outside of in-class requirements, teams must participate in interviews, technical reviews, presentations and the preparation of technical reports. The culmination of the course is a final presentation and technical review, followed by the delivery of the finished product. Prerequisite(s): CST2234, CST2235, CST8109, CST8285, CST8288." },
  { code: "ECO2200", name_en: "Economic Issues", name_ar: "شؤون اقتصادية", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting"], prerequisites: [], description_en: "Knowledge of contemporary economic issues is essential to understand the world in which we live. Students examine the fundamental economic issues faced by modern economies with an emphasis on the use of economic models to analyze economic developments accurately and objectively. Key economic problems faced by society, and policy alternatives that governments may use to deal with these problems are also investigated. Influence of economics on student civic, working, and personal lives is explored through lectures, discussions, and monitoring of current economic events." },
  { code: "ENL1813", name_en: "Communications I", name_ar: "مهارات التواصل 1", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting", "diploma-marketing", "diploma-management", "diploma-cp", "diploma-imd", "diploma-iawd"], prerequisites: [], description_en: "Communication remains an essential skill sought by employers, regardless of discipline or field of study. Using a practical, vocation-oriented approach, students develop stronger grammar and business writing skills to become effective business communicators. Through a combination of lectures, exercises, and independent learning, students practice writing, speaking, reading, listening, locating, and documenting information. They use technology to communicate professionally. Students develop and strengthen communication skills that contribute to success in both educational and workplace environments." },
  { code: "ENL1823", name_en: "Communications II", name_ar: "مهارات التواصل 2", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting", "diploma-marketing", "diploma-management", "diploma-cp", "diploma-imd", "diploma-iawd"], prerequisites: ["ENL1813"], description_en: "Students continue to expand their practical writing and speaking skills for successful communication in business. Using real-life scenarios and research skills, they produce informal reports and proposals, deliver presentations to a live audience supported by technology, and create a job search package. Students create professional documents, such as information reports, progress reports, justification/recommendation reports, summary reports, and minutes of meetings to develop up-to-date writing skills. The job search package includes employment readiness skills, resumes, persuasive cover letters, and interview techniques. In all written work, students continue to develop and enhance their grammar skills to meet professional, workplace standards. Prerequisite(s): ENL1813" },
  { code: "FIN2230", name_en: "Business Finance", name_ar: "التمويل التجاري", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting"], prerequisites: ["ACC2201"], description_en: "Students gain an understanding of the principles and uses of business finance. Topics covered include cash flow analysis, financial ratio analysis, financial planning, time value of money, risk and return, stock and bond valuation, and capital budgeting. Prerequisite(s): ACC2201" },
  { code: "GECU4100", name_en: "Technologies, Cultures & Societies", name_ar: "التقنيات والثقافات والمجتمعات", credit_hours: 1, course_type: "lecture", language: "bilingual", programs: ["bba-accounting", "bba-marketing", "bba-management", "basc-cs"], prerequisites: [], description_en: "Students examine the inter-relationships among our technologies, cultures, and societies. In this course, students examine how technologies have historically changed our cultural norms and societies and how they are increasingly and more rapidly doing so today. Students explore how technologies affect where we live and do business, how we live and do business, and how well and long we live and do business, and what this means for them as businesspeople and members of society." },
  { code: "GED0002", name_en: "Science of Well Being", name_ar: null, credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["diploma-imd", "diploma-iawd"], prerequisites: [], description_en: null },
  { code: "GED0020", name_en: "Entrepreneurial Mindset", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "How do entrepreneurs identify opportunities that others overlook? What are the underlying beliefs and assumptions that enable them to succeed, regardless of where they begin? Entrepreneurship requires people to identify problems in the environments in which they live and work and then reconceive them as opportunities for improvement. The entrepreneurial mindset ignites the process of searching for the intersection of one's interests and abilities with the needs of fellow human beings. Through experiential, problem-based learning, students explore specific beliefs and assumptions that enable entrepreneurs to succeed so that they can apply them to college or their chosen career path." },
  { code: "GED0022", name_en: "Positive Psychology – The Science of Happiness and Well-Being", name_ar: "علم النفس الإيجابي", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting", "diploma-marketing", "diploma-management", "diploma-cp"], prerequisites: [], description_en: "While fulfillment and well-being mark some people’s lives, many others remain dissatisfied with life. Positive Psychology is concerned with explaining how individuals and communities flourish through the scientific exploration of happiness, optimal human functioning, and civic engagement. The field of Positive Psychology has the objective of making life more satisfying and meaningful through interventions that promote and develop qualities such as self-knowledge, learned optimism, gratitude, mindfulness, resilience, and community connection. Students participate in both interactive lectures and on-line discussions, maintain weekly journals, and develop personal strengths through direct engagement with well-being initiatives. Details of the possible courses available at AC-Ottawa are available on the table below distributed over five themes as offered. The five themes are Arts in Society, Civil Life, Social and Cultural Understanding, Personal Understanding, and Science & Technology." },
  { code: "GED2234", name_en: "Contemporary Ethical Issues", name_ar: "القضايا الأخلاقية المعاصرة", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-marketing", "diploma-management"], prerequisites: [], description_en: "In today’s society there is increasingly more attention focused on questions of right or wrong, good or evil. Ethical issues relating to a wide variety of concerns are examined. Students clarify their own moral values and explore how these values impact the course of their lives. Students practice using tools and decision-making models to deal with personal and professional dilemmas." },
  { code: "GEEC3150", name_en: "Principles of Microeconomics", name_ar: "مبادئ الاقتصاد الجزئي", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting", "bba-marketing", "bba-management"], prerequisites: [], description_en: "Students will survey and apply conventional economic theory to national and international economic issues and events. Utilize the policy ideas and stances of contemporary economists to provoke discussion of prevailing economic issues. Topics of interest include Analysis of the economic impact of major social problems and issues and the role of government. Also, it will include the use of economic analysis to describe the social costs and benefits of government and public policy choices in addition to the use of technology and information resources to research economic problems and issues." },
  { code: "GEEC3250", name_en: "Principles of Macroeconomics ​", name_ar: "مبادئ الاقتصاد الكلي", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["bba-marketing", "bba-management"], prerequisites: ["GEEC3150"], description_en: "Students study macroeconomic theory at an introductory level. Topics treated include macroeconomic performance measures, economic growth, inflation, unemployment, money and banking, interest rates, exchange rates and government policy in a small, open economy like Kuwait. Prerequisite(s): GEEC3150" },
  { code: "GEN2003", name_en: "Healthy Lifestyle", name_ar: "نمط الحياة الصحية", credit_hours: 3, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting", "diploma-marketing", "diploma-management", "diploma-cp", "diploma-imd", "diploma-iawd"], prerequisites: [], description_en: "Are you eating healthy foods? Do you exercise regularly? Do you know how to prevent injuries and disease? These are some of the skills necessary to live a healthy lifestyle. Through self-evaluation, weekly journals, and hands-on exercises students assess their personal lifestyles and learn how to improve them." },
  { code: "GEPH3033", name_en: "Professional Integrity & Ethics", name_ar: "النزاهة والأخلاق المهنية", credit_hours: 3, course_type: "lecture", language: "en", programs: ["bba-accounting"], prerequisites: [], description_en: "Students study ethical theories and codes and explore how they are practiced and applied across different cultures and in various business contexts, such as employer employee relations, risk analysis, occupational and product safety, and environmental protection. By exploring the interaction of business and culture from an ethical perspective, students acquire the tools to allow them to examine, explain and debate the ethics of business decisions and practices." },
  { code: "LAW1702", name_en: "Business Law", name_ar: "قانون العمل", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: [], description_en: "Students are prepared for a business environment increasingly affected by laws. They learn how laws must be understood and applied by management in the conduct of business. They also learn how to analyze a business situation from a general legal perspective. Emphasis is placed on methods of dispute resolution, contracts, torts, employment law, methods of carrying on business, creditors' rights, sale of goods and marketing law." },
  { code: "MAT8001", name_en: "Technical Mathematics for Computer Science", name_ar: "الرياضيات التقنية لعلوم الكمبيوتر", credit_hours: 4, course_type: "lecture", language: "ar", programs: ["diploma-cp", "diploma-iawd"], prerequisites: [], description_en: "The study of algebraic and transcendental functions is an essential prerequisite to Calculus. Students manipulate algebraic expressions, solve algebraic equations and linear systems, and learn the properties of and graph algebraic and transcendental functions. Students investigate computer number systems in addition to Boolean algebra and logic to help solve problems involving computer systems. Students also study the addition and subtraction of vectors using vector components." },
  { code: "MGT2008", name_en: "Business Plan Applied", name_ar: "تطبيق خطة العمل", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: ["ACC0014", "MGT2232", "MKT0019"], description_en: "In this capstone course, students use key business management and entrepreneurial concepts to write and present a comprehensive business plan of their choice. The plan includes detailed marketing, operational and financial components thereby giving students a clear indication of the health of their business concept. Through a business plan project, students conceptualize, analyze, and compile a comprehensive business plan which articulates the steps for starting their new business. Prerequisite(s): MGT2232, MKT0019, ACC0014, and MGT2225" },
  { code: "MGT2201", name_en: "Business Fundamentals", name_ar: "أساسيات الأعمال", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting"], prerequisites: [], description_en: "Understanding the foundation of business is critical to anyone in the accounting field. This course gives students a broad overview of critical elements of business including an introduction to business structures, business processes, analyzing and various legal considerations, along with an overview of fundamental study practices that are essential in a business program. The combination of practical exercises and group work provides students with a strong foundation of business knowledge for future work." },
  { code: "MGT2202", name_en: "Emerging Technology for Business", name_ar: "التكنولوجيا الناشئة للأعمال", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: ["MGT2232"], description_en: "The use of new and existing technology and management tools are essential and a potential differentiator and advantage in today`s business world. Technology advances are occurring rapidly, therefore, an understanding of the change and the usage of technology are essential skills in today`s business environment. Students in this course will experiment, evaluate, and apply new technologies, understand the risks, opportunities, and rewards of new and existing technologies, and explore how to manage technology in their own venture. Prerequisite(s): MGT2232." },
  { code: "MGT2203", name_en: "Financial Management for Small Business", name_ar: "الإدارة المالية للشركات الصغيرة", credit_hours: 4, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: ["ACC0014"], description_en: "Students are introduced to financial statements and concepts that enable them to effectively partner with financial professionals as they launch their businesses and operations. Topics include balance sheets, income statements and cash flow statements and their interactions, financial analysis, and forecasting/budgeting. In addition, attention is focused on time value of money concepts, particularly as it relates to debt (interest payments and repayment schedules), as well as on various sources and types of financing for small businesses. Spreadsheet software is used extensively to present, analyze, and solve financial business issues. Prerequisite(s): ACC0014." },
  { code: "MGT2204", name_en: "Social Innovation", name_ar: "الابتكار المجتمعي", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: ["MGT2232"], description_en: "Social entrepreneurship and innovation are a rapidly developing field of business management where innovative thinking is applied towards solving social and environmental challenges within a market-based economy. The course will provide students with a practical introduction to social entrepreneurship and innovation by exploring various business models such as non-profit, for-profit, social, and indigenous enterprises. Topics such as sustainability, innovation, societal impact, and corporate social responsibility (CSR) will be explored. Students will compare various approaches to social innovation in sectors such healthcare, climate change, technology, finance and more. Through case studies, discussions and experiential learning, students will understand how social entrepreneurs use business knowledge and skills to transform communities and society at large. Prerequisite(s): MGT2232" },
  { code: "MGT2223", name_en: "Career Preparation for Entrepreneurs", name_ar: "الإعداد الوظيفي لرواد الأعمال", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: [], description_en: "Students focus on planning and enhancing the skills required to pursue the next phase of their career and life preparation. The course contains information on industry preparation, start-up life and post-secondary education with an emphasis on lifelong learning and personal development. Students focus on researching employment opportunities, expanding their professional network, employability skill assessment and interview preparation. This allows students to gain confidence, as they launch their professional business career. Students will also focus on analyzing various opportunities to expand their applied skills within complementary educational program areas and in their future endeavors, including what life in a start-up looks like." },
  { code: "MGT2224", name_en: "Managing for Business Success", name_ar: "إدارة العمل الناجح", credit_hours: 4, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: [], description_en: "Today's business owners and managers must not only recognize but excel in achieving organizational objectives for long term business success. This course examines the fundamental people and business management functions within a small to medium enterprise, including best practices related to recruitment, selection, onboarding, compensation, performance development, performance management, and leading a diverse workforce. Students will review the underlying management functions that support effective business operations within the framework of federal and provincial employment law. Learning is applied through the completion of a simulation, case studies, and a major project where students examine various organizational strategies leading to effective decision making and achievement of business objectives. Upon successful completion of this course, students will understand how to create a work culture that supports innovation and change." },
  { code: "MGT2225", name_en: "Project Management for Business Start-Ups", name_ar: "إدارة المشاريع للشركات الناشئة", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: [], description_en: "Entrepreneurs must know how to successfully plan and execute projects on time and within budget. Students learn the basic concepts of project management based on the best practices in this field. The tools and techniques include learning to identify project priorities, assigning and managing resources, budgeting, tracking progress and communicating with stakeholders. Hands-on practice is provided using project scheduling software to understand the work breakdown structure, critical-path activities, and resource loading. Case studies are used to demonstrate the practical application of each concept to planning and completion of project activities." },
  { code: "MGT2228", name_en: "Global Entrepreneurship", name_ar: "ريادة الأعمال العالمية", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: [], description_en: "Focus is on business entry into the international marketplace with special attention on identifying the barriers to entry. From a global entrepreneurship perspective, students examine the role of international trade research in identifying opportunities, the role of federal institutions in assisting entrepreneurs to identify threats and reduce the risk of failure. In addition, students learn the process of importing and exporting goods, the legal aspects of international trade, the growing role of CSR (Corporate Social Responsibility), the nature of trade financing when buying or selling internationally and the role of e-commerce in developing a global business presence. Students are exposed both to sources of information on the international marketplace and to the basic terminology being used in that marketplace." },
  { code: "MGT2232", name_en: "Entrepreneurship & Innovation", name_ar: "ريادة الأعمال والابتكار", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-management"], prerequisites: [], description_en: "In a world undergoing rapid and significant change, it is important to recognize the role, skills and characteristics associated with entrepreneurship in order to remain relevant. Topics include an overview of innovative thinking techniques, trend spotting, global entrepreneurship, marketing, market research, licensing, franchising, buying, and selling a business, and succession planning. Students put into practice entrepreneurial skills and strategies to recognize business opportunities. Through individual projects, students engage with entrepreneurs to discuss issues in today's marketplace and report on their findings." },
  { code: "MKT0018", name_en: "Marketing for Management & Entrepreneurship", name_ar: "التسويق للإدارة وريادة الأعمال", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: [], description_en: "The course provides an overview of the primary marketing functions used within an organization to successfully market products and services is provided. These functions include an overview of the strategic marketing process, environmental scanning, the ability to identify and segment markets, understanding of consumer buying behaviors and the importance of marketing research. This results in the development of a coordinated marketing program (product, price, promotion, and distribution channels). Students demonstrate decision-making skills through case study analysis. Decisions are analyzed based on the principles of corporate social responsibility and basic financial evaluation." },
  { code: "MKT0019", name_en: "Marketing Research", name_ar: "بحوث التسويق", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: ["MKT0018"], description_en: "Students apply the theory of sound marketing research to understand its importance in the managerial decision-making process in today's competitive marketplace. They apply current techniques to collect, record and analyze data relating to relevant business marketing challenges. Students work individually and in teams to develop and execute a research study for a product, service, or an industry client. This study involves a hands-on approach to specific delineation of problems, design of a research proposal along with collection of secondary and primary data. Various research techniques are used to develop and interpret the research results. Students present their study's findings and the results for management action. Prerequisite(s): MKT0018" },
  { code: "MKT2205", name_en: "Marketing Foundations", name_ar: "اساسيات التسويق", credit_hours: 4, course_type: "lecture", language: "en", programs: ["diploma-marketing"], prerequisites: [], description_en: "Students are introduced to the fundamentals of marketing, including the assessment of business environments to determine market potential. Students analyze the market to determine how to establish competitive advantage and assess buyer behavior. The four Ps of marketing (product, price, promotion, and place) are examined to determine the ideal set of marketing strategies and tactics to enhance an organization's competitive positioning." },
  { code: "MKT2206", name_en: "Product & Pricing Strategies", name_ar: "استراتجات المنتجات والتسعير", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-marketing"], prerequisites: ["MKT2205"], description_en: "Students acquire an in-depth appreciation for product and pricing strategies and tactics. Students gain a thorough appreciation for the new product development process, the strategies to effectively manage a product through its life cycle and the distinguishing factors between product and service marketing. Students study various product strategies to understand the conditions supporting each approach. With a firm grasp on product strategies students investigate supportive pricing strategies. Students discover theories that marketers apply to manage customer price sensitivity, competitive pricing actions and opportunities to segment the market based on price to maximize profitability. Students also learn the process and factors behind setting prices, apply formulas to assess the financial impacts of their pricing decisions and participate as a group member in solving pricing dilemmas and developing financial analyses as presented in a case study. Prerequisite(s): MKT2205" },
  { code: "MKT2207", name_en: "Marketing Channels", name_ar: "قنوات التسويق", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-marketing"], prerequisites: ["MKT2206"], description_en: "Students gain an understanding of how businesses leverage distribution channels within their marketing mix, both strategically and tactically. In addition to traditional direct and indirect distribution channels, students focus is on web-based and mobile electronic channels. Integration of distribution strategies with other marketing mix strategies is studied. Students apply this knowledge to specific situations to develop effective distribution channel strategies, solve distribution channel problems, and make recommendations to improve distribution channel efficiencies. Student teams use knowledge acquired to establish a marketing channel strategy, in conjunction with a joint MKT2283 Sales Management industry project. Prerequisite(s): MKT2206" },
  { code: "MKT2208", name_en: "Digital Marketing", name_ar: "التسويق الرقمي", credit_hours: 4, course_type: "lecture", language: "en", programs: ["diploma-marketing"], prerequisites: ["MKT2291"], description_en: "Students focus on digital marketing strategies using a broad range of online marketing tools. Establishing key messages, building engagement, and effectively communicating with customers is essential in the digital landscape today. Students build a strong foundation in content marketing and management systems, social media marketing, search engine marketing and measurement analytics, the cornerstones to an effective digital strategy. In the major team project, students have the opportunity to apply these digital marketing strategies to an industry client. Prerequisite(s): MKT2291" },
  { code: "MKT2213", name_en: "Skills for the Workplace", name_ar: "مهارات مكان العمل", credit_hours: 2, course_type: "lecture", language: "en", programs: ["diploma-marketing"], prerequisites: [], description_en: "Students focus on planning and enhancing the skills required to pursue the next phase of their career preparation. The course contains two streams: industry preparation and continuing higher education. Within the industry stream, students focus on researching employment opportunities, expanding their professional network, employability skill assessment and interview preparation. Within the continuing higher education stream, students review their future goals and explore the \"laddering\" agreements in place between the Business Marketing program and degree programs. Within both streams, students develop a professional LinkedIn profile and resume and benefit from interacting with various guest speakers." },
  { code: "MKT2216", name_en: "Skills Transferable to Business", name_ar: "المهارات القابلة للتحويل إلى الأعمال", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-marketing", "diploma-management"], prerequisites: [], description_en: "Learners develop foundational business skills to help them successfully graduate and prepare for the workforce. The focus is on preparing learners for professional employment by developing the following essential employability skills: personal and information management, leadership and teamwork, and communication and problem-solving techniques. Using a professional setting, learners participate in the following workshops: goal setting, time management, secondary research techniques, leadership and team building, decision making, project management, conflict resolution and speaking and presentation skills. Learners develop an awareness of their strengths and weaknesses and develop strategies for successful lifelong learning. Learners' ability to demonstrate these skills is essential as they participate in their academic and professional paths." },
  { code: "MKT2217", name_en: "Global Marketing", name_ar: "التسويق العالمي", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-marketing"], prerequisites: ["MKT2205"], description_en: "Students learn about the issues and the decisions required for businesses to succeed in the global marketplace. The course makes extensive use of electronic methods to characterize and exploit international marketing opportunities. By researching foreign markets, students understand how to evaluate suitable products/services for international target markets, establish efficient international distribution channels, conduct effective international promotion programs, establish profitable international pricing, and develop approaches to international financing. A key component is a group term project which involves preparing a country profile, a market audit, and a competitive analysis in preparation for the decision on how to grow the business in that country. Prerequisite(s): MKT2205" },
  { code: "MKT2218", name_en: "Digital Marketing", name_ar: "التسويق الرقمي", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: ["MKT0019"], description_en: "Students focus on understanding and implementing digital marketing strategies using a broad range of online marketing tools. Establishing key messages, building engagement, and effectively communicating with customers is essential in the digital landscape today. Students build a strong foundation in content marketing and management systems, social media marketing, search engine marketing and measurement analytics, all cornerstones to an effective digital strategy. Prerequisite(s): MKT0019" },
  { code: "MKT2260", name_en: "Industry Marketing Plan", name_ar: "خطة التسويق الصناعية", credit_hours: 4, course_type: "lecture", language: "en", programs: ["diploma-marketing"], prerequisites: ["MKT2207", "MKT2283"], description_en: "Students apply concepts to an industry client. Working in teams, students create a marketing plan for local business. The course works in tandem with MKT 2261 (field work), MKT 2208 (Digital Marketing) and MKT 2292 (IMC 2) allowing students to develop and practice cross-discipline and teamwork skills. Students conduct an in-depth analysis of internal and external marketing factors to uncover a target market and positioning opportunity for their industry client. Students then take this marketing strategy and develop a complementary marketing mix to leverage the identified market opportunity, a detailed implementation plan and financial analysis to prove the financial viability of their plan. Prerequisite(s): MKT2207, MKT2283, MKT2285 and MKT2291" },
  { code: "MKT2261", name_en: "Marketing Plan Project Field Work", name_ar: "مشروع خطة التسويق للعمل الميداني", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-marketing"], prerequisites: ["MKT2207", "MKT2283"], description_en: "Student teams are assigned to work with an industry client to research all aspects of the client's business including all pertinent internal and industry micro and macro environmental factors. Students use primary and secondary research tools and methodologies to assess the competitive industry set and conduct an in-depth customer analysis. The knowledge created from this infield work guides the creation of the Marketing Plan Objectives, strategies and supporting marketing mix programs within the MKT2260 course. Students also learn unique approaches to client management along with enhanced team presentation skills. Prerequisite(s): MKT2207, MKT2283" },
  { code: "MKT2282", name_en: "Professional Selling", name_ar: "البيع الاحترافي", credit_hours: 4, course_type: "lecture", language: "en", programs: ["diploma-marketing"], prerequisites: ["MKT2205"], description_en: "Students develop the selling skills they require during a business career. Major topics studied include the importance of the selling function to all types of organizations, ethical issues in selling and steps in the selling process. Students become familiar with the Canadian Competition Act, and the laws protecting consumers. Students also learn how to develop enduring customer relationships and the important role of customer service in relationship building. Focus is on the students preparing and delivering a sales presentation and a written proposal. Prerequisite(s): MKT2205" },
  { code: "MKT2283", name_en: "Sales Management", name_ar: "إدارة المبيعات", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-marketing"], prerequisites: ["MKT2282"], description_en: "Students are provided with insight and knowledge pertaining to the key issues involved in sales management. Emphasis is placed on the four key functional areas (planning, developing, directing/leading and evaluating) within sales management and the skills required to manage sales teams and achieve profitability. The transferability of these skills to other management situations is stressed. Students apply their knowledge and practice their sales management skills on an individual and group basis. Students are required to participate in a major group project focused on assessing the effectiveness of a sales manager within the sales and marketing organization of a chosen company. Prerequisite(s): MKT2282" },
  { code: "MKT2285", name_en: "Marketing Research", name_ar: "بحوث التسويق 2", credit_hours: 4, course_type: "lecture", language: "en", programs: ["diploma-marketing"], prerequisites: ["MKT2206", "QUA0008"], description_en: "Students apply the theory of sound marketing research to understand its importance to managerial decision-making in today's competitive marketplace. They apply current techniques to collect, record and analyze data relating to relevant business marketing challenges. Working in teams, students develop and execute a full research study for industry. This study involves specific delineation of problems, design of a research proposal along with collection of secondary and primary data. Teams create and implement a quantitative research effort using a survey they design and a qualitative effort by holding a focus group. Teams complete the term by interpreting their study's findings and presenting the results for management action. Prerequisite(s): MKT2206, QUA0008." },
  { code: "MKT2291", name_en: "Integrated Marketing Communications 1", name_ar: "الاتصالات التسويقية المتكاملة 1", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-marketing"], prerequisites: [], description_en: "Students are provided with an in-depth look at the marketing communications mix elements. The role of advertising and promotion, and how they are related to the overall marketing plan are examined in depth. Through practical applications, students learn to develop the skills needed to plan and manage a comprehensive Integrated Marketing Communications (IMC) plan, which includes consumer segmentation, development of appropriate objectives, positioning and competitive creative strategies. Students are introduced to current design software and gain experience creating ad layouts. Prerequisite(s): MKT2205 and MKT2206" },
  { code: "MKT2292", name_en: "Integrated Marketing Communications II New Media", name_ar: "الاتصالات التسويقية المتكاملة 2", credit_hours: 4, course_type: "lecture", language: "en", programs: ["diploma-marketing"], prerequisites: ["MKT2291"], description_en: "Gain further insight into current trends and developments in interactive and Internet communications, media relations, event marketing and sponsorship, tradeshow, and public relations with a special emphasis on applying IMC strategies in a business-to-business environment including market segmentation and analysis. Students demonstrate and develop their decision-making skills through case analysis based on an industry client situation. The major team project involves the development of a detailed IMC Execution Plan, an element of the overall industry client marketing plan project. The comprehensive IMC Execution Plan includes campaign objectives, specific media vehicle selection and scheduling within a designated budget. Prerequisite(s): MKT2291" },
  { code: "MTM6101", name_en: "Introduction to Photography", name_ar: null, credit_hours: 3, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Understanding how to use professional-level digital cameras as well as creating impactful images that communicate and engage the viewer is an essential skill for photography. Students discover the capabilities of professional-level cameras by exploring the functions beyond point and click. By using manual modes and taking advantage of the many features a professional camera has to offer, students examine the technology, techniques, and theory of photography. Students take photos in a variety of settings and environments, exploring best practices during production to minimize post-production issues. Ways of using photography as visual communication are delved into, with opportunities for students to showcase their storytelling abilities through their own photographs." },
  { code: "MTM6130", name_en: "Web Development I", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Designing and developing websites in browsers starts with the basics of two coding languages: HTML and CSS. Students discover web design and modern web standards to build sites that work on any sized device. Students apply current best practices in web design and coding techniques as they complete responsive website building projects using industry standard tools." },
  { code: "MTM6160", name_en: "Digital Graphics", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "The creation of digital art requires an understanding of the modern techniques, tools and file formats the industry uses. By exploring and utilizing current software, students become familiar with the process of planning for and executing digital graphics and design assets. Students examine best practices for file size and format, optimization, and the development of assets for use both online and in print." },
  { code: "MTM6162", name_en: "Design Foundations", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Design is the study of visual communication that combines images, words and ideas to convey information to an audience. Through a hands-on approach to design, students become objective rather than subjective about good design. Through fundamental design theories and project-based learning, students discover fundamental design rules, principles in layout, typography, and colour theory. Modern industry-standard software is used interactively to execute design processes, methodologies, best practices, and design solutions for a client-based project." },
  { code: "MTM6200", name_en: "Video Foundations", name_ar: null, credit_hours: 6, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Creating engaging videos requires a combination of technical skills and creativity. Students explore planning and pre-production as well as take a hands-on approach to video production. Video, audio, and lighting technology and tools are introduced, building on the basic photography techniques and best practices. Through hands-on learning, students work through pre-production and production of both video and audio. Emphasis is placed on ensuring the best quality result when transitioning to post-production to minimize corrections during editing." },
  { code: "MTM6201", name_en: "Web Development II", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Websites should be universally designed to meet everyone's needs. Students expand on their basic knowledge of HTML and CSS to incorporate topics such as accessibility, search engine optimization, fluid design, advanced media queries, CSS framework, and web animation. Students explore the mobile-first paradigm, create sites that behave across a range of platforms, utilize existing CSS frameworks, and create fun, interactive and dynamic media projects. Prerequisites: MTM6130." },
  { code: "MTM6231", name_en: "Content Management Systems I", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: [], prerequisites: [], description_en: "In the fast-paced media industry, not every project needs to be built from scratch. Content Management Systems (CMS) offer pre-built functionality that designers and developers can work with to deliver diverse, feature-rich, modern websites. Students install, configure, customize and style websites built on these systems. Students assess how and when using a CMS is appropriate, when it can benefit projects and clients and how to integrate a variety of social media systems within their CMS." },
  { code: "MTM6260", name_en: "User Experience Design I", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "User experience design (UX) is a design process that focuses on enhancing and positively impacting the user's experience for both usability and visual dynamics. Students create user interfaces by applying UX strategies, user research, information architecture, interaction design, usability testing, visual design, and content strategy. Going beyond creating graphics, students focus on how responsive website interfaces must be based on user needs and expectations while aligning business goals. Students design effective interfaces that allow improved workflow while integrating user feedback and usability data collected through focus groups. Practical and effective planning for user interfaces is practiced through completing interactive projects. Prerequisites: MTM6162." },
  { code: "MTM6302", name_en: "Web Development III", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Users have come to expect a dynamic, interactive experience when exploring sites; this interactivity is fundamental to creating a modern user experience. Building on knowledge of HTML and CSS, students use JavaScript and related client-side technologies to build interactivity into websites and applications. Best practices in coding are elaborated on and put into concepts including functions, conditional statements and loops as they complete dynamic interactive website building projects. Prerequisites: MTM6201." },
  { code: "MTM6304", name_en: "Media Project Planning", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Effective management of time, resources, clients and teams is crucial to the success of any project. Students utilize the theory of project management, following industry standard guidelines and best practices. With client-based projects, the full project cycle is executed, including planning, managing risks, intellectual property rights, communication, project scope, project documentation and closure. Prerequisites: MTM6200 and MTM6201." },
  { code: "MTM6305", name_en: "User Experience Design II", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Interfaces should be intuitive, easy to use and satisfy customer needs so that products and services are successful. Through team-based projects, the user experience (UX) design process is introduced for tablet and mobile app interfaces. Using a practical and applied approach, students understand user experience design, from data gathering methodologies to interaction design and user interface testing. Students apply design principles and guidelines to create well-thought-out interactions and cohesive responsive interfaces, focusing on the end-user experience. Prerequisites: MTM6260." },
  { code: "MTM6306", name_en: "Video Production", name_ar: null, credit_hours: 5, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Digital media relies on a strong story to communicate a message and reach the audience. Working with industry standard approaches and techniques, students will move beyond the basics of film and video and develop a deeper knowledge and skill set that will enable better, more thoughtful and nuanced story telling. Students will learn more advanced lighting, audio and editing as well as looking at multicamera and live stream techniques and technology. They will also look at the role digital media plays in business today and work on productions that prepare them for a role in the digital media world. Prerequisites: MTM6200." },
  { code: "MTM6403", name_en: "Motion Design", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Motion design products can be used in a broad range of media. Students expand their understanding of the world of motion design and visual effects to help students build precision, control and fluency of expression within time-based digital environments. Through practical editing projects, students gain a solid foundation of motion design and effects techniques that support their creativity and enhance their digital skill set. Prerequisites: MTM6306." },
  { code: "MTM6406", name_en: "Business Marketing", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Business acumen plays a vital role in the success of interactive media design professionals. Students periodically interact with industry professionals who share their current, in-depth knowledge in their area of expertise. Occasional guest lectures allow students to acquire the latest relevant and specialized knowledge about finance, intellectual property, ethics, employment and more. Through hands on learning and group work students develop a better understanding and the necessary techniques, tools and industry standards for conducting business." },
  { code: "MTM6460", name_en: "Applied Projects", name_ar: null, credit_hours: 6, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Integration of theory and practice in the context of a real-world industry project reinforces learning for students while affording industry partners a low-risk opportunity to explore innovative solutions. Students work with real clients or on industry-reflective projects, using teamwork and acquired skills to build real-world applications and multimedia products. Working in teams, students plan, manage and develop a project through the full project cycle, from proposal to post-mortem while working on technically challenging client-based projects. Students present final project work to invested parties to highlight the process and outcomes of the developed project. Prerequisites: MTM6302, MTM630, and MTM6305/MTM6306." },
  { code: "MTM6461", name_en: "Digital Portfolio", name_ar: null, credit_hours: 4, course_type: "unknown", language: "unknown", programs: ["diploma-imd"], prerequisites: [], description_en: "Transitioning from an educational setting to a professional work environment requires preparation. Students focus on preparing for entry into the field through personal brand projects including professional development plans, business cards, CVs, creative resumes, and digital portfolios. Students gain industry knowledge through guest speakers. Prerequisites: MTM6160." },
  { code: "QUA0002", name_en: "Business Mathematics", name_ar: "رياضيات الأعمال التجارية", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-marketing", "diploma-management"], prerequisites: [], description_en: "Students review basic arithmetic and algebra, as well as mathematic tools and concepts required for solving problems found in a business environment. Problem-solving areas include cost-volume profit analysis, linear functions and systems of equations, index numbers, markup and markdowns, terms of invoicing and business finance." },
  { code: "QUA0008", name_en: "Statistics", name_ar: "الإحصاء", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-marketing"], prerequisites: ["QUA0002"], description_en: "Descriptive methods of data classification, sampling, collecting, organizing, and presentation of data in order to evaluate various business situations in a decision making context. Computations through appropriate computer software are emphasized. Students learn mathematical methods for descriptive statistics, frequency distributions and measures of location and variation. An introduction of regression and correlation analysis including the examination of the regression equation, coefficient of correlation and determination and the standard error. Time series analysis is covered including computations for short-term forecasting. Finally, students learn basic probability to solve business related problems. Prerequisite(s): QUA0002" },
  { code: "QUA2210", name_en: "Basic Business Mathematics", name_ar: "أساسيات رياضيات الأعمال التجارية", credit_hours: 4, course_type: "lecture", language: "bilingual", programs: ["diploma-accounting"], prerequisites: [], description_en: "The essentials of arithmetic and its applications, including fractions, decimals, percentages, mathematics of buying and selling, payroll, taxes, depreciation, and inventory are examined. Students are introduced to the mathematics of finance, including simple and compound interest, annuities, sinking funds, amortization, and consumer credit." },
  { code: "RET2213", name_en: "eCommerce", name_ar: "التجارة الاكترونية", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: [], description_en: "Setting up and managing e-commerce websites is an essential skill in today`s multichannel economy. Whether you are an entrepreneur or working for a larger organization, develop a broad understanding of all that goes into a successful e-commerce site. This course provides the fundamentals of eCommerce, with a particular emphasis on the strategy, challenges, and applications of eCommerce - including security issues, billing and payment systems, and supply chain. Emphasis is on applied learning, learning from real-world successes and failures via cases. The course will culminate in the development of an eCommerce website." },
  { code: "RET2214", name_en: "Retail Management", name_ar: "إدارة البيع بالتجزئة", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: ["RET2213"], description_en: "Students are introduced to retail specific strategies and best practices to adapt, navigate, and manage in an ever-changing retail environment. An in-depth look at how the physical and online environments (omni-channel) impact a consumer`s shopping experience are explored. Learning outcomes are integrated throughout the course with case studies and in-class activities. The importance of retail marketing and branding, the retail mix, macro and micro environmental issues, supply chain optimization, pricing strategies, and inventory management are also reviewed. Prerequisite(s): RET2213" },
  { code: "RET2223", name_en: "Professional Selling", name_ar: "البيع الإحترافي", credit_hours: 3, course_type: "lecture", language: "en", programs: ["diploma-management"], prerequisites: [], description_en: "Developing the trust-based relationship selling requires a sales professional through weekly role playing and a final mock sales presentation with a product/ service of your choice. Students analyze buyer motivators, their purchasing processes and overcome customer concerns with confidence. Sales ethics and their legal implications are examined. Students demonstrate the importance of collaborative, two-way communication in trust-based selling and the business environment." },
];

const BY_CODE: Record<string, CatalogCourse> = Object.fromEntries(
  COURSES.map((c) => [c.code, c]),
);

/** Look up a single catalog course by its code (e.g. "ACC2201"). */
export function getCourse(code: string): CatalogCourse | undefined {
  return BY_CODE[code];
}

/** All catalog courses belonging to a given program slug. */
export function coursesByProgram(program: string): CatalogCourse[] {
  return COURSES.filter((c) => c.programs.includes(program as never));
}
